__global__ void
srad_kernel(
          float lambda,
          int rows,
          int cols,
          long size_I,
          int *iN,
          int *iS,
          int *jE,
          int *jW,
          float *dN,
          float *dS,
          float *dW,
          float *dE,
          float q0sqr,
          float *c,
          float *J
)
{
  int idx = get_global_id(0);

  if (idx >= size_I) return;

  int i = idx / cols;
  int j = idx % cols;

  float Jc = J[idx];

  dN[idx] = J[iN[i] * cols + j] - Jc;
  dS[idx] = J[iS[i] * cols + j] - Jc;
  dW[idx] = J[i * cols + jW[j]] - Jc;
  dE[idx] = J[i * cols + jE[j]] - Jc;

  float G2 = (dN[idx]*dN[idx] + dS[idx]*dS[idx] 
            + dW[idx]*dW[idx] + dE[idx]*dE[idx]) / (Jc*Jc);

  float L = (dN[idx] + dS[idx] + dW[idx] + dE[idx]) / Jc;

  float num = (0.5*G2) - ((1.0/16.0)*(L*L));
  float den = 1 + (.25*L);
  float qsqr = num/(den*den);

  den = (qsqr-q0sqr) / (q0sqr * (1+q0sqr));
  float coeff = 1.0 / (1.0+den);

  if (coeff < 0) coeff = 0;
  else if (coeff > 1) coeff = 1;

  c[idx] = coeff;
}

__global__ void
srad2_kernel(
          float lambda,
          int rows,
          int cols,
          long size_I,
          int *iN,
          int *iS,
          int *jE,
          int *jW,
          float *dN,
          float *dS,
          float *dW,
          float *dE,
          float *c,
          float *J
)
{
  int idx = get_global_id(0);

  if (idx >= size_I) return;

  int i = idx / cols;
  int j = idx % cols;

  float cN = c[idx];
  float cS = c[iS[i] * cols + j];
  float cW = c[idx];
  float cE = c[i * cols + jE[j]];

  float D = cN * dN[idx] + cS * dS[idx] + cW * dW[idx] + cE * dE[idx];

  J[idx] = J[idx] + 0.25*lambda*D;
}
